def lcs_length(a,b):
    # dynamic programming
    n,m=len(a),len(b)
    dp = [0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            cur=dp[j]
            if a[i-1]==b[j-1]:
                dp[j]=prev+1
            else:
                dp[j]=max(dp[j], dp[j-1])
            prev=cur
    return dp[m]

def norm(s):
    return normalize_ar(s)

def lcs_ratio(a,b):
    A=norm(a)
    B=norm(b)
    if not A or not B: return 0.0
    l=lcs_length(A,B)
    return l/max(len(A),len(B))

